import{_ as e,o as l,c as a,a4 as n}from"./chunks/framework._in6GHBg.js";const x=JSON.parse('{"title":"有机推断套路","description":"","frontmatter":{},"headers":[],"relativePath":"chemistry/Chem-Review-Routine-007-有机推断套路-V1.0-20260405.md","filePath":"chemistry/Chem-Review-Routine-007-有机推断套路-V1.0-20260405.md"}'),i={name:"chemistry/Chem-Review-Routine-007-有机推断套路-V1.0-20260405.md"};function s(r,t,d,o,h,g){return l(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="有机推断套路" tabindex="-1">有机推断套路 <a class="header-anchor" href="#有机推断套路" aria-label="Permalink to &quot;有机推断套路&quot;">​</a></h1><p><strong>高考化学选考必考题——有机推断题解题模板</strong></p><hr><h2 id="题型认知" tabindex="-1">题型认知 <a class="header-anchor" href="#题型认知" aria-label="Permalink to &quot;题型认知&quot;">​</a></h2><h3 id="题目特征" tabindex="-1">题目特征 <a class="header-anchor" href="#题目特征" aria-label="Permalink to &quot;题目特征&quot;">​</a></h3><ul><li>给出有机物的转化关系图</li><li>给出部分物质的分子式或结构简式</li><li>给出反应条件或特征现象</li><li>要求推断未知物结构，回答相关问题</li></ul><h3 id="分值分布" tabindex="-1">分值分布 <a class="header-anchor" href="#分值分布" aria-label="Permalink to &quot;分值分布&quot;">​</a></h3><ul><li>通常15分（选考题）</li><li>5-7个小问</li><li>前3-4问基础，后几问综合</li></ul><hr><h2 id="解题五步法" tabindex="-1">解题五步法 <a class="header-anchor" href="#解题五步法" aria-label="Permalink to &quot;解题五步法&quot;">​</a></h2><h3 id="第一步-计算不饱和度-30秒" tabindex="-1">第一步：计算不饱和度（30秒） <a class="header-anchor" href="#第一步-计算不饱和度-30秒" aria-label="Permalink to &quot;第一步：计算不饱和度（30秒）&quot;">​</a></h3><p><strong>公式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Ω = (2C + 2 + N - H - X)/2</span></span>
<span class="line"><span></span></span>
<span class="line"><span>C：碳原子数</span></span>
<span class="line"><span>H：氢原子数</span></span>
<span class="line"><span>N：氮原子数</span></span>
<span class="line"><span>X：卤素原子数</span></span></code></pre></div><p><strong>不饱和度与结构的关系</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">Ω</th><th style="text-align:left;">可能结构</th></tr></thead><tbody><tr><td style="text-align:center;">0</td><td style="text-align:left;">饱和链状（烷烃、醇、醚）</td></tr><tr><td style="text-align:center;">1</td><td style="text-align:left;">一个双键或一个环（烯烃、酮、醛、羧酸、酯）</td></tr><tr><td style="text-align:center;">2</td><td style="text-align:left;">两个双键/一个三键/一个双键+一个环/两个环</td></tr><tr><td style="text-align:center;">4</td><td style="text-align:left;">可能含苯环（苯环Ω=4）</td></tr><tr><td style="text-align:center;">≥4</td><td style="text-align:left;">可能含苯环或多个不饱和结构</td></tr></tbody></table><p><strong>示例</strong>：</p><ul><li>C₆H₆：Ω = (12+2-6)/2 = 4 → 可能含苯环</li><li>C₄H₈O：Ω = (8+2-8)/2 = 1 → 可能含C=O或C=C</li></ul><hr><h3 id="第二步-找突破口-1分钟" tabindex="-1">第二步：找突破口（1分钟） <a class="header-anchor" href="#第二步-找突破口-1分钟" aria-label="Permalink to &quot;第二步：找突破口（1分钟）&quot;">​</a></h3><p><strong>突破口类型1：特征现象</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">现象</th><th style="text-align:left;">推断</th></tr></thead><tbody><tr><td style="text-align:left;">能使溴水褪色</td><td style="text-align:left;">含C=C、C≡C或醛基</td></tr><tr><td style="text-align:left;">能使KMnO₄溶液褪色</td><td style="text-align:left;">含C=C、C≡C、醛基或苯的同系物</td></tr><tr><td style="text-align:left;">银镜反应</td><td style="text-align:left;">含醛基（-CHO）</td></tr><tr><td style="text-align:left;">与新制Cu(OH)₂反应生成砖红色沉淀</td><td style="text-align:left;">含醛基（-CHO）</td></tr><tr><td style="text-align:left;">与FeCl₃溶液显紫色</td><td style="text-align:left;">含酚羟基</td></tr><tr><td style="text-align:left;">与Na反应放出H₂</td><td style="text-align:left;">含-OH或-COOH</td></tr><tr><td style="text-align:left;">与Na₂CO₃/NaHCO₃反应放出CO₂</td><td style="text-align:left;">含-COOH</td></tr><tr><td style="text-align:left;">酯的香味</td><td style="text-align:left;">含酯基（-COO-）</td></tr></tbody></table><p><strong>突破口类型2：反应条件</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">条件</th><th style="text-align:left;">反应类型</th><th style="text-align:left;">官能团变化</th></tr></thead><tbody><tr><td style="text-align:left;">光照</td><td style="text-align:left;">取代（烷基卤代）</td><td style="text-align:left;">烷烃→卤代烃</td></tr><tr><td style="text-align:left;">浓H₂SO₄，170℃</td><td style="text-align:left;">消去</td><td style="text-align:left;">醇→烯烃</td></tr><tr><td style="text-align:left;">浓H₂SO₄，加热</td><td style="text-align:left;">酯化、硝化、磺化</td><td style="text-align:left;">醇+酸→酯</td></tr><tr><td style="text-align:left;">NaOH水溶液，加热</td><td style="text-align:left;">水解</td><td style="text-align:left;">卤代烃→醇；酯→酸+醇</td></tr><tr><td style="text-align:left;">NaOH醇溶液，加热</td><td style="text-align:left;">消去</td><td style="text-align:left;">卤代烃→烯烃</td></tr><tr><td style="text-align:left;">Cu/Ag，加热</td><td style="text-align:left;">氧化</td><td style="text-align:left;">醇→醛</td></tr><tr><td style="text-align:left;">Ni，加热（H₂）</td><td style="text-align:left;">加成（还原）</td><td style="text-align:left;">烯烃→烷烃；醛→醇</td></tr><tr><td style="text-align:left;">银氨溶液，水浴</td><td style="text-align:left;">氧化</td><td style="text-align:left;">醛→羧酸</td></tr><tr><td style="text-align:left;">新制Cu(OH)₂，加热</td><td style="text-align:left;">氧化</td><td style="text-align:left;">醛→羧酸</td></tr></tbody></table><p><strong>突破口类型3：分子式变化</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">变化</th><th style="text-align:left;">推断</th></tr></thead><tbody><tr><td style="text-align:left;">分子量增加16</td><td style="text-align:left;">可能加了一个O（氧化）</td></tr><tr><td style="text-align:left;">分子量增加28</td><td style="text-align:left;">可能加了CO或C₂H₄</td></tr><tr><td style="text-align:left;">分子量减少18</td><td style="text-align:left;">可能脱了一个H₂O（消去或酯化）</td></tr><tr><td style="text-align:left;">分子量减少44</td><td style="text-align:left;">可能脱了一个CO₂</td></tr></tbody></table><hr><h3 id="第三步-顺藤摸瓜-2分钟" tabindex="-1">第三步：顺藤摸瓜（2分钟） <a class="header-anchor" href="#第三步-顺藤摸瓜-2分钟" aria-label="Permalink to &quot;第三步：顺藤摸瓜（2分钟）&quot;">​</a></h3><p><strong>从已知推未知</strong>：</p><ul><li>已知A，根据转化条件和分子式推B</li><li>已知B，根据转化条件和分子式推C</li><li>...</li></ul><p><strong>常用转化关系</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>醇 → 醛 → 羧酸 → 酯</span></span>
<span class="line"><span>↑              ↓</span></span>
<span class="line"><span>└── 水解 ←───────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>烯烃 → 醇 → 醛 → 羧酸</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>卤代烃 → 醇</span></span></code></pre></div><p><strong>官能团转化关系图</strong>（必须熟记）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>        烷烃</span></span>
<span class="line"><span>          ↓ 取代</span></span>
<span class="line"><span>        卤代烃</span></span>
<span class="line"><span>          ↓ 水解/消去</span></span>
<span class="line"><span>        醇 ←───────┐</span></span>
<span class="line"><span>          ↓ 氧化    │ 水解</span></span>
<span class="line"><span>        醛          │</span></span>
<span class="line"><span>          ↓ 氧化    │</span></span>
<span class="line"><span>        羧酸 → 酯化 → 酯</span></span></code></pre></div><hr><h3 id="第四步-验证推断-1分钟" tabindex="-1">第四步：验证推断（1分钟） <a class="header-anchor" href="#第四步-验证推断-1分钟" aria-label="Permalink to &quot;第四步：验证推断（1分钟）&quot;">​</a></h3><p><strong>验证方法</strong>：</p><ol><li>检查分子式是否匹配</li><li>检查反应条件是否合理</li><li>检查所有转化是否都能发生</li></ol><p><strong>常见错误</strong>：</p><ul><li>醇氧化：只有含α-H的醇才能氧化成醛或酮</li><li>消去反应：只有含β-H的卤代烃/醇才能消去</li></ul><hr><h3 id="第五步-规范作答" tabindex="-1">第五步：规范作答 <a class="header-anchor" href="#第五步-规范作答" aria-label="Permalink to &quot;第五步：规范作答&quot;">​</a></h3><p><strong>书写要求</strong>：</p><ul><li>结构简式要规范（碳骨架清晰，官能团位置正确）</li><li>化学方程式要配平，注明条件</li><li>同分异构体书写不重复不遗漏</li></ul><hr><h2 id="同分异构体书写套路" tabindex="-1">同分异构体书写套路 <a class="header-anchor" href="#同分异构体书写套路" aria-label="Permalink to &quot;同分异构体书写套路&quot;">​</a></h2><h3 id="书写步骤" tabindex="-1">书写步骤 <a class="header-anchor" href="#书写步骤" aria-label="Permalink to &quot;书写步骤&quot;">​</a></h3><ol><li><strong>确定不饱和度</strong>：判断可能含有的官能团</li><li><strong>写碳链异构</strong>：主链由长到短</li><li><strong>写位置异构</strong>：官能团位置变化</li><li><strong>写官能团异构</strong>：不同官能团（如醇和醚）</li></ol><h3 id="常见同分异构体数目" tabindex="-1">常见同分异构体数目 <a class="header-anchor" href="#常见同分异构体数目" aria-label="Permalink to &quot;常见同分异构体数目&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">分子式</th><th style="text-align:center;">类型</th><th style="text-align:center;">同分异构体数</th></tr></thead><tbody><tr><td style="text-align:center;">C₄H₁₀</td><td style="text-align:center;">烷烃</td><td style="text-align:center;">2（正丁烷、异丁烷）</td></tr><tr><td style="text-align:center;">C₅H₁₂</td><td style="text-align:center;">烷烃</td><td style="text-align:center;">3</td></tr><tr><td style="text-align:center;">C₄H₈</td><td style="text-align:center;">烯烃</td><td style="text-align:center;">3（含顺反异构4种）</td></tr><tr><td style="text-align:center;">C₄H₉-</td><td style="text-align:center;">丁基</td><td style="text-align:center;">4</td></tr><tr><td style="text-align:center;">C₅H₁₁-</td><td style="text-align:center;">戊基</td><td style="text-align:center;">8</td></tr><tr><td style="text-align:center;">C₆H₄Cl₂</td><td style="text-align:center;">二氯苯</td><td style="text-align:center;">3（邻、间、对）</td></tr></tbody></table><h3 id="限定条件的同分异构体" tabindex="-1">限定条件的同分异构体 <a class="header-anchor" href="#限定条件的同分异构体" aria-label="Permalink to &quot;限定条件的同分异构体&quot;">​</a></h3><p><strong>常见限定条件</strong>：</p><ul><li>能发生银镜反应 → 含醛基</li><li>能与FeCl₃显色 → 含酚羟基</li><li>能水解 → 含酯基或卤代烃</li><li>只有两种化学环境的H → 结构高度对称</li></ul><hr><h2 id="高频考点速查" tabindex="-1">高频考点速查 <a class="header-anchor" href="#高频考点速查" aria-label="Permalink to &quot;高频考点速查&quot;">​</a></h2><h3 id="官能团性质速查" tabindex="-1">官能团性质速查 <a class="header-anchor" href="#官能团性质速查" aria-label="Permalink to &quot;官能团性质速查&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">官能团</th><th style="text-align:center;">特征反应</th><th style="text-align:left;">现象</th></tr></thead><tbody><tr><td style="text-align:center;">C=C</td><td style="text-align:center;">加成（Br₂、H₂）</td><td style="text-align:left;">溴水褪色</td></tr><tr><td style="text-align:center;">-OH（醇）</td><td style="text-align:center;">与Na反应</td><td style="text-align:left;">产生H₂</td></tr><tr><td style="text-align:center;">-OH（酚）</td><td style="text-align:center;">与FeCl₃反应</td><td style="text-align:left;">显紫色</td></tr><tr><td style="text-align:center;">-CHO</td><td style="text-align:center;">银镜反应</td><td style="text-align:left;">生成银镜</td></tr><tr><td style="text-align:center;">-CHO</td><td style="text-align:center;">与新制Cu(OH)₂反应</td><td style="text-align:left;">砖红色沉淀</td></tr><tr><td style="text-align:center;">-COOH</td><td style="text-align:center;">与NaHCO₃反应</td><td style="text-align:left;">产生CO₂</td></tr><tr><td style="text-align:center;">-COO-</td><td style="text-align:center;">水解</td><td style="text-align:left;">酸性条件下生成酸和醇</td></tr></tbody></table><h3 id="反应类型判断" tabindex="-1">反应类型判断 <a class="header-anchor" href="#反应类型判断" aria-label="Permalink to &quot;反应类型判断&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">反应类型</th><th style="text-align:center;">特征</th><th style="text-align:left;">例子</th></tr></thead><tbody><tr><td style="text-align:center;">取代</td><td style="text-align:center;">原子或基团被替换</td><td style="text-align:left;">烷烃卤代、酯化、水解</td></tr><tr><td style="text-align:center;">加成</td><td style="text-align:center;">不饱和键断裂，加原子或基团</td><td style="text-align:left;">烯烃加Br₂、加H₂</td></tr><tr><td style="text-align:center;">消去</td><td style="text-align:center;">脱去小分子（H₂O、HX）</td><td style="text-align:left;">醇→烯烃、卤代烃→烯烃</td></tr><tr><td style="text-align:center;">氧化</td><td style="text-align:center;">加氧或去氢</td><td style="text-align:left;">醇→醛→酸、燃烧</td></tr><tr><td style="text-align:center;">还原</td><td style="text-align:center;">加氢或去氧</td><td style="text-align:left;">醛→醇、烯烃→烷烃</td></tr><tr><td style="text-align:center;">聚合</td><td style="text-align:center;">小分子聚合成高分子</td><td style="text-align:left;">乙烯→聚乙烯</td></tr></tbody></table><hr><h2 id="经典题型示例" tabindex="-1">经典题型示例 <a class="header-anchor" href="#经典题型示例" aria-label="Permalink to &quot;经典题型示例&quot;">​</a></h2><h3 id="示例-推断某有机物结构" tabindex="-1">示例：推断某有机物结构 <a class="header-anchor" href="#示例-推断某有机物结构" aria-label="Permalink to &quot;示例：推断某有机物结构&quot;">​</a></h3><p><strong>题目信息</strong>：</p><ul><li>A的分子式为C₄H₈O₂</li><li>A能在碱性条件下水解生成B和C</li><li>B能被氧化成D，D能发生银镜反应</li><li>C与金属钠反应放出H₂</li></ul><p><strong>推断过程</strong>：</p><ol><li>Ω = (8+2-8)/2 = 1 → 可能含C=O或C=C</li><li>A能水解 → 含酯基（-COO-）</li><li>B能被氧化且产物能发生银镜反应 → B是醇，且含α-H</li><li>C与Na反应 → C是酸或醇（结合A是酯）→ C是酸</li><li>推断：A是乙酸乙酯 CH₃COOCH₂CH₃ <ul><li>B是乙醇 CH₃CH₂OH</li><li>C是乙酸 CH₃COOH</li><li>D是乙醛 CH₃CHO</li></ul></li></ol><hr><h2 id="faq-常见问题" tabindex="-1">FAQ（常见问题） <a class="header-anchor" href="#faq-常见问题" aria-label="Permalink to &quot;FAQ（常见问题）&quot;">​</a></h2><h3 id="q1-看到转化关系图完全没有思路怎么办" tabindex="-1">Q1：看到转化关系图完全没有思路怎么办？ <a class="header-anchor" href="#q1-看到转化关系图完全没有思路怎么办" aria-label="Permalink to &quot;Q1：看到转化关系图完全没有思路怎么办？&quot;">​</a></h3><p><strong>A</strong>：</p><ol><li>先看分子式，算不饱和度</li><li>找特征现象或反应条件的突破口</li><li>从已知物开始，一步一步推</li><li>熟记「醇-醛-酸-酯」转化关系</li></ol><h3 id="q2-同分异构体总是写不全怎么办" tabindex="-1">Q2：同分异构体总是写不全怎么办？ <a class="header-anchor" href="#q2-同分异构体总是写不全怎么办" aria-label="Permalink to &quot;Q2：同分异构体总是写不全怎么办？&quot;">​</a></h3><p><strong>A</strong>：</p><ol><li>按步骤来：碳链异构→位置异构→官能团异构</li><li>记住常见数目（C₄H₉-有4种，C₅H₁₁-有8种）</li><li>写完后用系统命名法检查（命名相同就是重复）</li><li>多练习，培养感觉</li></ol><h3 id="q3-有机方程式总是写错怎么办" tabindex="-1">Q3：有机方程式总是写错怎么办？ <a class="header-anchor" href="#q3-有机方程式总是写错怎么办" aria-label="Permalink to &quot;Q3：有机方程式总是写错怎么办？&quot;">​</a></h3><p><strong>A</strong>：</p><ol><li>记住典型反应（加成、取代、氧化、消去）</li><li>注意反应条件（浓H₂SO₄加热是酯化，NaOH加热是水解）</li><li>酯化反应：酸脱羟基，醇脱氢</li><li>水解反应：酯→酸+醇</li></ol><h3 id="q4-结构简式怎么写得规范" tabindex="-1">Q4：结构简式怎么写得规范？ <a class="header-anchor" href="#q4-结构简式怎么写得规范" aria-label="Permalink to &quot;Q4：结构简式怎么写得规范？&quot;">​</a></h3><p><strong>A</strong>：</p><ol><li>碳骨架清晰（主链、支链分明）</li><li>官能团写完整（-CHO不能写成-COH）</li><li>苯环写六边形（圆圈或三条双键）</li><li>酯基写-COO-（不要写成-OOC-）</li></ol><hr><h2 id="实战演练-checklist" tabindex="-1">实战演练 checklist <a class="header-anchor" href="#实战演练-checklist" aria-label="Permalink to &quot;实战演练 checklist&quot;">​</a></h2><p>拿到一道有机推断题：</p><ul><li>[ ] 计算不饱和度，推测可能结构</li><li>[ ] 找突破口（特征现象、反应条件、分子式变化）</li><li>[ ] 顺藤摸瓜，从已知推未知</li><li>[ ] 画转化关系图验证</li><li>[ ] 规范书写结构简式和方程式</li></ul><hr><h2 id="文档信息" tabindex="-1">文档信息 <a class="header-anchor" href="#文档信息" aria-label="Permalink to &quot;文档信息&quot;">​</a></h2><p><strong>文档编号</strong>: Chem-Review-Routine-007<br><strong>版本</strong>: V1.0<br><strong>编制日期</strong>: 2026-04-05<br><strong>适用题型</strong>: 有机推断题（15分，选考）<br><strong>配套文档</strong>: Chem-Learn-Detail-004 有机化学基础详解</p><hr><p><em>有机推断题的关键是「找突破口」，突破口往往藏在特征现象和反应条件里。</em></p>`,88)])])}const p=e(i,[["render",s]]);export{x as __pageData,p as default};
